fit = polyfit(ARwet, L_Dm, 1);
y   = polyval(fit, x);

figure('Color','w','Position',[200 200 800 550])   % white bg + larger figure %[output:226df822]

% ---- Scatter ----
scatter(sqrt(ARwet), L_Dm, 70, ... %[output:226df822]
        'filled', ... %[output:226df822]
