%%
 
%%      OPTIMAL SPEED ESTIMATION FOR DIFFERENT PHASES

%Cruise,Max Range,"Minimum Thrust (CDo=CDi�)"
%Climb,Max Angle,"Minimum Thrust (CDo=CDi�)"
%Loiter,Max Time,"Minimum Power (3CDo=CDi�)"
%Descent,Max Glide,"Minimum Thrust (CDo=CDi)"

% ==========================
% AUTHOR = MONISHA VIJAYAN (AE25M037)
%==========================



% BEFORE PAYLOAD DROP
% ==========================
% For our UAV
% ==========================
AR=9.686 %[output:30012ba2]
MTOW=68.516 %[output:9b5d77bb]
e=1.78*(1-0.045*AR^0.68)-0.64 %for rectangular wing %[output:66dc9179]
rho=1.225 % @ cruising altitude = 200m %[output:713f8bda]
b=2 %[output:939e01f8]
s=(b^2)/AR %[output:5c79cc04]
vcr=22;
Cl=(2*MTOW)/(rho*vcr^2*s);
k=1/(pi*AR*e) %[output:6fba89d5]
CDo=k*Cl^2 %[output:6a6c325a]
v0=30; 
L_D_max = 11.595 %[output:67b5c5ee]
%% =========================
%  Optimum velocity during CLIMB1  
% ==========================
gamma=8;
Clclimb=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Clclimb(v).^2);
v_optimal_climb=fsolve(fun,v0); %[output:373ec2f9]
D=(0.5*rho*s*v_optimal_climb^2*2*k*Clclimb(v_optimal_climb)^2);
T_Wcl=(sind(gamma)+(D/MTOW));
T=(T_Wcl*MTOW) %[output:12f78dbe]
Pclimb1=(T*v_optimal_climb) %[output:9b35129c]
fprintf('Optimum velocity during climb1 = %.3f\n',v_optimal_climb) %[output:04b16933]
fprintf('T/W ratio for climb1 phase = %.3f\n',T_Wcl) %[output:2da390d0]
fprintf('Power required in Climb1 phase = %.3f\n',Pclimb1) %[output:9b06c531]
%% =========================
%  Optimum velocity during CRUISE1 
% ==========================
gamma=0;
Clcruise=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Clcruise(v).^2);
v_optimal_cruise=fsolve(fun,v0); %[output:7ed0ee4a]
D=(0.5*rho*s*v_optimal_cruise^2*2*k*Clcruise(v_optimal_cruise)^2);
T_Wcr=(sind(gamma)+(D/MTOW));
T=(T_Wcr*MTOW) %[output:095ff22f]
Pcruise1=(T*v_optimal_cruise);
fprintf("Optimum velocity during cruise1 = %.3f\n",v_optimal_cruise) %[output:5a541acd]
fprintf("T/W ratio for cruise1 phase = %.3f\n",T_Wcr) %[output:0508a8c8]
fprintf("Power required in cruise1 phase = %.3f\n",Pcruise1) %[output:6401f171]
%% =========================
%  Optimum velocity during DESCENT1 
% ==========================
gamma=-8;
Cldescent=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Cldescent(v).^2);
v_optimal_descent=fsolve(fun,v0); %[output:7d4dd6e4]
D=(0.5*rho*s*v_optimal_descent^2*2*k*Cldescent(v_optimal_descent)^2);
T_Wds=abs((sind(gamma)+(D/MTOW)));
T=(T_Wds*MTOW);
Pdescent1=(T*v_optimal_descent);
fprintf("Optimum velocity during descent1 = %.3f\n",v_optimal_descent) %[output:2ae26533]
fprintf("T/W ratio for descent1 phase = %.3f\n",T_Wds) %[output:2d881da3]
fprintf("Power required in descent1 phase = %.3f\n",Pdescent1) %[output:53494da5]

%%==========================
% AFTER PAYLOAD DROP
% ==========================
% For our UAV
% ==========================
MTOW=57.94;
Cl_ref=(2*68.516)/(rho*vcr^2*s);
CDo=k*Cl_ref^2; 
L_Dm=1/(2*sqrt(k*CDo)); 
v0=30; 
%% =========================
%  Optimum velocity during LOITER
% ==========================
gamma=0;
Clloiter=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(3*0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Clloiter(v).^2);
v_optimal_loiter=fsolve(fun,v0); %[output:3df392db]
D=0.5*rho*s*v_optimal_loiter^2*(CDo+k*Clloiter(v_optimal_loiter)^2);
T_Wl=(sind(gamma)+(D/MTOW));
T=(T_Wl*MTOW);
Ploiter=(T*v_optimal_loiter);
fprintf("Optimum velocity during loiter = %.3f\n",v_optimal_loiter) %[output:0a154e39]
fprintf("T/W ratio for loiter phase = %.3f\n",T_Wl) %[output:77fad9b5]
fprintf("Power required in loiter phase = %.3f\n",Ploiter) %[output:7a9ec11a]
%% =========================
%  Optimum velocity during CLIMB2
% ==========================
gamma=8;
Clclimb=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Clclimb(v).^2);
v_optimal_climb=fsolve(fun,v0); %[output:5ef2ff8d]
D=0.5*rho*s*v_optimal_climb^2*2*CDo;
T_Wcl=(sind(gamma)+(D/MTOW));
T=(T_Wcl*MTOW);
Pclimb2=(T*v_optimal_climb);
fprintf("Optimum velocity during climb2 = %.3f\n",v_optimal_climb) %[output:0fad12a2]
fprintf("T/W ratio for climb2 phase = %.3f\n",T_Wcl) %[output:3896cccc]
fprintf("Power required in Climb2 phase = %.3f\n",Pclimb2) %[output:27e298a0]
%% =========================
%  Optimum velocity during CRUISE2
% ==========================
gamma=0;
Clcruise=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Clcruise(v).^2);
v_optimal_cruise=fsolve(fun,v0); %[output:14811e55]
D=0.5*rho*s*v_optimal_cruise^2*2*CDo;
T_Wcr=(sind(gamma)+(D/MTOW));
T=(T_Wcr*MTOW) %[output:87f2b123]
Pcruise2=(T*v_optimal_cruise);
fprintf("Optimum velocity during cruise2 = %.3f\n",v_optimal_cruise) %[output:0e2c5786]
fprintf("T/W ratio for cruise2 phase = %.3f\n",T_Wcr) %[output:014994e2]
fprintf("Power required in cruise2 phase = %.3f\n",Pcruise2) %[output:66a805c8]
%% =========================
%  Optimum velocity during DESCENT2
% ==========================
gamma=-8;
Cldescent=@(v)(2*MTOW*cosd(gamma))/(rho*s*v.^2);
fun=@(v)(0.5*rho*s*v.^2*CDo)-(0.5*rho*s*v.^2.*k.*Cldescent(v).^2);
v_optimal_descent=fsolve(fun,v0); %[output:096d061d]
D=0.5*rho*s*v_optimal_descent^2*2*CDo;
T_Wds=abs((sind(gamma)+(D/MTOW)));
T=(T_Wds*MTOW) %[output:0abb5a01]
Pdescent2=(T*v_optimal_descent);
fprintf("Optimum velocity during descent2 = %.3f\n",v_optimal_descent) %[output:425b0878]
fprintf("T/W ratio for descent2 phase = %.3f\n",T_Wds) %[output:9b5bb773]
fprintf("Power required in descent2 phase = %.3f\n",Pdescent2) %[output:4bf98e06]
%%
Lift_cruise = MTOW %[output:09ead103]
Drag_cruise = Lift_cruise/L_D_max %[output:416ce975]
thrust_required_cruise = Drag_cruise %[output:740781de]
C_L_cruise = @(v) Lift_cruise/(0.5*rho*s*v^2) %[output:8eb32561]
C_d_i_cruise_func = @(v) C_L_cruise(v)^2/(pi*e*AR) %[output:40b4215c]
% Drag_function_cruise = @(v)(0.5*rho*s*v^2*(CDo + C_d_i_cruise_func(v))) - Drag_cruise

Drag_function_cruise = @(v)(0.5*rho*s*v^2*(2*C_d_i_cruise_func(v))) - Drag_cruise %[output:41248af8]
optimal_velocity_cruise = fsolve(Drag_function_cruise,v0) %[output:3ca2bfa9] %[output:46568baa]
Power_required_cruise = thrust_required_cruise*optimal_velocity_cruise %[output:90be0989]
P_W_cruse = Power_required_cruise/MTOW %[output:461fc0a7]

CDo = C_d_i_cruise_func(optimal_velocity_cruise) %[output:469e2b68]
%%
% climb_1
AR=9.6 %[output:386b55bd]
MTOW=68.516;
e=1.78*(1-0.045*AR^0.68)-0.64 %for rectangular wing %[output:472a0253]
rho=1.225; % @ cruising altitude = 200m
b=2;
s=(b^2)/AR %[output:78313b73]
vcr=22;
Cl=(2*MTOW)/(rho*vcr^2*s) %[output:32994b7b]
k=1/(pi*AR*e) %[output:38e9ee5c]
%CDo=k*Cl^2
v0=30; 
L_D_max = 15.595 %[output:2a2f770d]
gamma = 8 %[output:11f79647]
Lift = MTOW*cosd(gamma) %[output:23575390]
Drag = 2*Lift/(sqrt(3)*L_D_max) %[output:0cad5b74]
%Drag = Lift/(L_D_max)
thrust_required_climb = Drag + MTOW*sind(gamma) %[output:20d3d491]
C_L_climb = @(v) Lift/(0.5*rho*s*v^2) %[output:6f3a52c5]
C_d_i_climb_func = @(v) C_L_climb(v)^2/(pi*e*AR) %[output:765d47b2]
Drag_function = @(v)(0.5*rho*s*v^2*(CDo + C_d_i_climb_func(v))) - Drag %[output:16bb081a]
optimal_velocity_climb = fsolve(Drag_function,v0) %[output:2ffa5964] %[output:91e0c5c9]
Power_required_climb = thrust_required_climb*optimal_velocity_climb %[output:856c2d78]
P_W_climb = Power_required_climb/MTOW %[output:163444e9]
%%
% cruise_1
Lift_cruise = MTOW %[output:4773abb5]
Drag_cruise = Lift_cruise/L_D_max %[output:844c24c9]
thrust_required_cruise = Drag_cruise %[output:956a09a4]
C_L_cruise = @(v) Lift_cruise/(0.5*rho*s*v^2) %[output:0c6c87fb]
C_d_i_cruise_func = @(v) C_L_cruise(v)^2/(pi*e*AR) %[output:4a1d4c94]
% Drag_function_cruise = @(v)(0.5*rho*s*v^2*(CDo + C_d_i_cruise_func(v))) - Drag_cruise

Drag_function_cruise = @(v)(0.5*rho*s*v^2*(2*C_d_i_cruise_func(v))) - Drag_cruise %[output:7ad1a277]
optimal_velocity_cruise = fsolve(Drag_function_cruise,v0) %[output:16e0bd92] %[output:98298732]
Power_required_cruise = thrust_required_cruise*optimal_velocity_cruise %[output:5b6326de]
P_W_cruse = Power_required_cruise/MTOW %[output:2a2195a9]

